215→    override fun performReload() {
216→        mReloadRequired = true
217→        val newCardList = col.filterToValidCards(mCardList)
218→        if (newCardList.isEmpty()) {
219→            finishWithoutAnimation()
220→            return
221→        }
222→        mIndex = getNextIndex(newCardList)
223→        mCardList = newCardList.toLongArray()
